#include <vector>
#include <string>
#include <unordered_set>

using namespace std;

long long solve(string s, vector<long long> order, long long k) {
    long long n = s.size();
    if (k == 0) return 0;

    unordered_set<long long> marked;
    long long total = 0;

    for (long long t = 0; t < n; ++t) {
        long long pos = order[t];
        marked.insert(pos);

        // Calculate the number of new valid substrings introduced by this '*'
        long long left = pos;
        while (left >= 0 && marked.find(left) == marked.end()) {
            left--;
        }
        left++; // first position to the left that is not marked

        long long right = pos;
        while (right < n && marked.find(right) == marked.end()) {
            right++;
        }
        right--; // first position to the right that is not marked

        // The new substrings are all that include pos and any substring between left and right
        long long new_substrings = (pos - left + 1) * (right - pos + 1);
        total += new_substrings;

        if (total >= k) {
            return t;
        }
    }

    return -1;
}
